#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int a, b, c;
        scanf("%d %d %d", &a, &b, &c);
        int left = (a == 0) + (b == 0) + (c == 0);
        int right = (a == 1) + (b == 1) + (c == 1);
        printf("%d\n", (left > 0 && right > 0) ? 1 : 0);
    }
    return 0;
}

